{
    List<List<Integer>> result = new ArrayList<>();
    // Start backtracking with an empty list as the current permutation
    backtrack(result, new ArrayList<>(), nums);
    return result;
}

private void backtrack(List<List<Integer>> list, List<Integer> tempList, int [] nums){
    if(tempList.size() == nums.length){
        list.add(new ArrayList<>(tempList)); // Add a new list to avoid reference issues
    } else {
        for(int i = 0; i < nums.length; i++){
            if(tempList.contains(nums[i])) continue; // Element already exists, skip
            tempList.add(nums[i]);
            backtrack(list, tempList, nums);
            tempList.remove(tempList.size() - 1); // Remove the last element added for backtracking
        }
    }
}

