     * >>> appx("ROUGH", "PESKY")
     * "appx(ROUGH, PESKY) = 0"
     * >>> appx("A", "A")
     * "appx(A, A) = 1"
     */
    public static String appx(String word1, String word2)  {
        // Convert the words to sets to make counting easier
        Set<Character> word1Set = new HashSet<>(word1.chars().mapToObj(c -> (char) c).collect(Collectors.toList()));
        Set<Character> word2Set = new HashSet<>(word2.chars().mapToObj(c -> (char) c).collect(Collectors.toList()));
        // The number of letters in the intersection
        int common = 0;
        // The sum of the lengths of the words
        int lengthSum = 0;
        // Count the common letters
        for (char c : word1Set) {
            if (word2Set.contains(c)) {
                common += 1;
            }
